import Foundation

enum Environment: String {
    case development = "dev.api.example.com"
    case staging = "stg.api.example.com"
    case production = "api.example.com"
}

class APIClient {
    private let session: URLSession
    private let environment: Environment

    init(environment: Environment) {
        self.environment = environment
        self.session = URLSession.shared
    }

    func getUserData(completion: @escaping (Result<Data, Error>) -> Void) {
        let url = URL(string: "\(environment.rawValue)/users")!
        let request = URLRequest(url: url)
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            completion(.success(data!))
        }.resume()
    }

    func authenticate(username: String, password: String, completion: @escaping (Result<Data, Error>) -> Void) {
        let url = URL(string: "\(environment.rawValue)/auth")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        let parameters = ["username": username, "password": password]
        request.httpBody = try! JSONSerialization.data(withJSONObject: parameters, options: [])
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            completion(.success(data!))
        }.resume()
    }
}